import { useState } from "react";
import ServerIcon from "./ServerIcon";

import classes from "./ServerList.module.css";

const ServerSidebar = () => {
  const [selectedServer, setSelectedServer] = useState(1);

  return (
    <nav>
      <div className={classes["server-list"]}>
        <ServerIcon id="1" setSelectedServer={setSelectedServer} selectedServer = {selectedServer}></ServerIcon>
        <ServerIcon id="2" setSelectedServer={setSelectedServer}></ServerIcon>
        <ServerIcon id="3" setSelectedServer={setSelectedServer}></ServerIcon>
      </div>
    </nav>
  );
};

export default ServerSidebar;
